args.sparql:
SELECT ?building ?buildingLabel ?height
WHERE {
  ?building wdt:P31 wd:Q4117189;
            wdt:P577 ?completionDate;
            wdt:P2048 ?height.
  ?building rdfs:label ?buildingLabel.
  FILTER (LANG(?buildingLabel) = "en").
  FILTER (SUBSTR(STR(?completionDate), 1, 4) >= "1900").
  FILTER (SUBSTR(STR(?completionDate), 1, 4) <= "2000").
  FILTER NOT EXISTS { ?building wdt:P582 ?demiseDate }.
}
ORDER BY DESC(?height)
LIMIT 4
